// Normalize scraped jobs.
const results = [];

for (const item of $input.all()) {
  const j = item.json;

  const url = (j.jobUrl || j.url || j.link || '').trim();
  const title = j.title || j.jobTitle || j.position || '';
  const company = j.company || j.companyName || '';
  const location = j.location || j.jobLocation || '';
  const description = j.description || j.jobDescription || j.descriptionHtml || '';

  if (!url || !title || !description || description.length < 100) {
    continue;
  }

  results.push({
    json: {
      url,
      title,
      company,
      location,
      description
    }
  });
}

console.log(`Jobs after normalization: ${results.length}`);
return results;

// Regex-only relocation + sponsorship filter.
const results = [];

const HIGH_PATTERNS = [
  /visa sponsorship/i,
  /sponsorship available/i,
  /provide visa/i,
  /work permit sponsorship/i,
  /relocation support/i,
  /relocation package/i,
  /kennismigrant/i,
  /ind sponsor/i,
  /visa sponsor/i,
  /sponsoring visas/i,
  /we sponsor/i,
  /sponsor your visa/i,
  /global mobility/i
];

const MEDIUM_PATTERNS = [
  /eu blue card/i,
  /highly skilled migrant/i,
  /work authorization/i,
  /must be eligible to work/i,
  /relocate to netherlands/i,
  /immigration support/i,
  /work permit/i
];

for (const item of $input.all()) {
  const job = item.json;

  const text = `${job.title}\n${job.description}`.toLowerCase();

  const matchedHigh = HIGH_PATTERNS
    .filter(r => r.test(text))
    .map(r => r.source.replace(/\\/g, ''));

  const matchedMedium = MEDIUM_PATTERNS
    .filter(r => r.test(text))
    .map(r => r.source.replace(/\\/g, ''));

  if (matchedHigh.length === 0 && matchedMedium.length === 0) {
    continue;
  }

  const confidence = matchedHigh.length > 0 ? 'high' : 'medium';

  results.push({
    json: {
      url: job.url,
      title: job.title,
      company: job.company,
      location: job.location,
      description: job.description,
      relocation_signals: [...matchedHigh, ...matchedMedium].join(', '),
      relocation_confidence: confidence
    }
  });
}

console.log(`Jobs after regex relocation filter: ${results.length}`);
return results;

// Build cover letter LLM request.
const results = [];

const coverLetterTemplate = `Dear Hiring Manager,

I am excited to apply for the [JOB_TITLE] position at [COMPANY_NAME].

I am currently working as a Senior Software Engineer (SDE3 / Associate Vice President) at JPMorgan Chase Asset & Wealth Management, where I work on AI-native engineering platforms, MCP server infrastructure, developer tooling, and large-scale cloud systems.

What strongly attracted me to [COMPANY_NAME] is [SPECIFIC_REASON_ABOUT_COMPANY_OR_PRODUCT].

In my current role at JPMorgan Chase, I:
- Architect MCP server infrastructure enabling LLM-native access to design systems and engineering workflows
- Build AI-native platforms such as Connect Studio supporting design-to-code and story-to-code workflows
- Work across React, TypeScript, Python, AWS, and agentic systems

Previously at Aurigo Software Technologies, I spent nearly 6 years building enterprise-scale frontend and AI-integrated platforms.

I am particularly interested in relocating to the Netherlands through a visa sponsorship / kennismigrant opportunity.

Thank you for your consideration.

Best regards,
Shirsak Sahoo`;

for (const item of $input.all()) {
  const {
    url,
    title,
    company,
    location,
    description,
    relocation_signals,
    relocation_confidence
  } = item.json;

  const trimmedDescription = description.substring(0, 4000);

  const payload = {
    model: 'unsloth/Qwen3.5-9B-GGUF:Q6_K',
    temperature: 0.4,
    max_tokens: 9000,
    top_p: 0.9,
    repeat_penalty: 1.1,
    messages: [
      {
        role: 'system',
        content: 'You are an expert cover letter writer. Generate concise professional cover letters tailored to the role.'
      },
      {
        role: 'user',
        content: `Template:\n${coverLetterTemplate}\n\nJob Description:\n${trimmedDescription}\n\nCompany: ${company}\nRole: ${title}\nLocation: ${location}\n\nGenerate a personalized cover letter using the template and job description.`
      }
    ],
    extra_body: {
      chat_template_kwargs: {
        enable_thinking: false
      }
    }
  };

  results.push({
    json: {
      _job: {
        url,
        title,
        company,
        location,
        description: trimmedDescription,
        relocation_signals,
        relocation_confidence
      },
      _llmPayload: payload
    }
  });
}

return results;

// Assemble final row.
const llmItem = $input.first();
const reqItem = $('Build Cover Letter Request').first();

if (!llmItem?.json || !reqItem?.json?._job) {
  return [];
}

const coverLetter = (llmItem.json?.choices?.[0]?.message?.content || '').trim();

if (!coverLetter) {
  return [];
}

const job = reqItem.json._job;

return [
  {
    json: {
      date: new Date().toISOString().split('T')[0],
      company: job.company || '',
      title: job.title || '',
      location: job.location || '',
      url: job.url || '',
      relocation_signals: job.relocation_signals || '',
      relocation_confidence: job.relocation_confidence || '',
      cover_letter: coverLetter,
      status: 'Not Applied'
    }
  }
];
